// NŒUD 6 — Rédaction LLM CONV-A (No-FS)
// Correctif A2 — 2026-03-16 : Merge déterministe depuis Nœud 5 (runner) + Nœud 5b (N1)
// Supprime la race condition execSync(cat n1_path) précédente.
// Appel API Anthropic — résultats en mémoire, pas d'écriture disque dans ce nœud.

"use strict";
const https = require("https");
const { execSync } = require("child_process");

// ── Merge deux branches : Nœud 5 (main) + Nœud 5b (sensibilité N1) ─────────
// $input.all() retourne les items des deux branches du Merge n8n
const _items = $input.all();

// Branche principale = celle qui contient result_data (runner) OU révision (compteur)
const _dataMain = _items.find(i => i.json.result_data != null)?.json
               || _items[0]?.json
               || {};

// Branche N1 = celle qui contient rapport_n1 sans result_data
const _dataN1 = _items.find(i => i.json.rapport_n1 != null && i.json.result_data == null)?.json
              || _items.find(i => i.json.rapport_n1 != null)?.json
              || {};

// Données fusionnées
const data = { ..._dataMain };

// rapport_n1 : priorité branche 5b, fallback payload existant (cas révision)
let rapport_n1 = _dataN1.rapport_n1 || _dataMain.rapport_n1 || null;
const wp_id       = data.wp_id;
const ctx         = data.llm_context || {};
const sim         = data.result_data?.simulation || {};
const vrd         = data.result_data?.verdict    || {};
const n1          = data.n1_resume_llm           || {};
const ncWarnings  = data.nc_non_bloquantes       || [];

// Préparer les données stress-tests pour le prompt
const stress_n1 = data.result_data?.simulation?.stress_n1 || {};
const stress_n2 = data.result_data?.simulation?.stress_n2 || [];
const stress_n2_str = stress_n2.length > 0
  ? "Calculé par le runner Python (8 combinaisons) :\n" + stress_n2.map(s => `  - ${s.label}: ${s.traj}`).join("\n")
  : "Non calculé";
const tableau_s2 = data.result_data?.simulation?.tableau_S2 || [];
const tableau_s2_str = tableau_s2.length > 0
  ? tableau_s2.map(r => `t=${r.t}: F=${r.F?.toFixed(4)||"?"} R=${r.R?.toFixed(4)||"?"} FR=${r.FR?.toFixed(4)||"?"}`).join("\n")
  : "Non disponible";

const prompt_conva = `Tu es CONV-A (Rédacteur MEPA V6.2 Fortifiée).
Rédige le rapport complet S1→S7 pour le WP suivant.

IDENTITÉ WP :
- WP-ID : ${wp_id}
- Cas : ${ctx.cas || "?"}
- Période : ${ctx.periode || "?"}
- Cluster : ${ctx.cluster || "?"}
- Sa : ${ctx.sa || "?"}
- Trajectoire attendue : ${ctx.trajectoire_attendue || "?"}

VARIABLES MEPA (codées par CONV-E) :
${JSON.stringify(ctx.mepa_full_vars || {}, null, 2)}

RÉSULTATS SIMULATION EXACTS (mepa_runner_v2_gamma v2.1) :
⚠ UTILISE UNIQUEMENT CES VALEURS — NE PAS INVENTER DE CHIFFRES
- Trajectoire diagnostiquée : ${sim.traj || "?"}
- t_bascule : ${sim.t_bascule ?? "null — aucune bascule F>R détectée"}
- ΔC_rel : ${sim.dC_rel ?? "null"} | ΔI_rel : ${sim.dI_rel ?? "null"}
- FR_max : ${sim.FR_max ?? "?"} | FR_final : ${sim.FR_final ?? "?"}
- C_max : ${sim.C_max ?? "?"} | C_final : ${sim.C_final ?? "?"}
- S_final : ${sim.S_final ?? "?"} | L_final : ${sim.L_final ?? "?"}
- Robustesse N1 : ${vrd.robustesse || "?"} — Trajs N1 : ${JSON.stringify(vrd.trajs_set_n1 || [])}
- Concordance : ${vrd.concordance_attendue ? "OUI" : "NON"}
- Stress N1 optimiste : ${stress_n1.optimiste?.traj || "?"} | pessimiste : ${stress_n1.pessimiste?.traj || "?"}
- Stress N2 (8 combinaisons) :
${stress_n2_str}
- Sensibilité N1 : ${n1.verdict || "NON_CALCULÉ"} — ${n1.note_s4 || ""}
${ncWarnings.length > 0 ? `\nVARIABLES NC NON-BLOQUANTES : ${ncWarnings.join(", ")}\nAppliquer le Silence Socratique V6.2.` : ""}

TABLEAU F(t)/R(t) EXACT DU RUNNER (à reproduire tel quel en S2) :
${tableau_s2_str}

RÈGLES RÉDACTION V6.2 — OBLIGATOIRES :
1. γ s'écrit avec le symbole Unicode γ (U+03B3). Jamais "g", jamais "gamma".
2. S2 OBLIGATOIRE : reproduire le tableau F(t)/R(t) ci-dessus avec les valeurs EXACTES.
   Mentionner explicitement FR_max=${sim.FR_max ?? "?"} dans le corps du texte.
3. VALEURS NULL : si t_bascule/dC_rel/dI_rel sont null, l'écrire explicitement dans S2
   avec explication : "aucune bascule F>R détectée — F reste inférieur à R sur toute la simulation".
4. DISCORDANCE (règle anti-narrative-smoothing §4.3 Manuel Gouvernance) :
   Si trajectoire diagnostiquée ≠ attendue, écrire en S2 EXACTEMENT ce format :
   "Divergence documentée — la simulation produit (X) au lieu de (Y) attendue.
   [Condition technique non atteinte : ex. F reste < R sur toute la simulation, t_bascule=null].
   Potentielle zone de réfutation [RF1: EROI<5 sans techno / RF2: absence (a)/(d) malgré E_split>0.7 / RF3: complexité croissante avec EROI déclinant] si confirmée sur d'autres cas."

   INTERDIT (narrative smoothing) :
   - Toute phrase du type "ce résultat est cohérent avec [événement historique]"
   - Toute justification a posteriori de la divergence par l'histoire
   - Toute phrase critiquant le modèle ("incapacité du runner", "limite du modèle")
   - Tout effort pour "expliquer" pourquoi la simulation a raison malgré la divergence

   AUTORISÉ en S6/S7 uniquement (pas en S2) :
   - Discussion des implications théoriques de la divergence pour MEPA
   - Hypothèses sur les paramètres qui pourraient capturer la trajectoire attendue
5. S4 OBLIGATOIRE : intégrer les résultats stress-tests N1 et N2 avec leurs trajectoires.
   Pour N2, REPRODUIRE OBLIGATOIREMENT le tableau complet des 8 combinaisons ci-dessous,
   avec la trajectoire pour chacune. Si stress_n2_str = "Non calculé", l'indiquer explicitement.
   Format obligatoire en S4 :
   "Stress N2 (8 combinaisons) :
   [liste des 8 combinaisons avec trajectoires depuis les données runner]"
   Conclure sur la robustesse globale N1+N2.
6. S7 : synthèse comparative avec le corpus MEPA (cluster ${ctx.cluster || "?"}).
7. Format : Markdown structuré, titres ## S1 à ## S7.

ALERTES : ${JSON.stringify(ctx.alertes || [])}
DÉFI MEPA : ${ctx.defi_mepa || "Non renseigné"}

Rédige maintenant le rapport complet.`;

const apiKey  = $env.ANTHROPIC_API_KEY;
const payload = JSON.stringify({
  model: "claude-sonnet-4-20250514",
  max_tokens: 4000,
  temperature: 0,
  system: "Tu es CONV-A, le Rédacteur scientifique du projet MEPA V6.2 Fortifiée. Tu produis des rapports WP rigoureux en 7 sections S1-S7, en respectant strictement les règles de nomenclature et les données numériques exactes du runner. Tu ne lisses jamais les divergences de trajectoire.",
  messages: [{ role: "user", content: prompt_conva }]
});

const options = {
  hostname: "api.anthropic.com",
  path: "/v1/messages",
  method: "POST",
  headers: {
    "Content-Type": "application/json",
    "x-api-key": apiKey,
    "anthropic-version": "2023-06-01",
    "Content-Length": Buffer.byteLength(payload)
  }
};

const rapport_md = await new Promise((resolve, reject) => {
  const req = https.request(options, (res) => {
    let body = "";
    res.on("data", chunk => body += chunk);
    res.on("end", () => {
      try {
        // Vérifier le statut HTTP avant de parser
        if (res.statusCode !== 200) {
          reject(new Error(`API HTTP ${res.statusCode} : ${body.slice(0,300)}`));
          return;
        }
        const parsed = JSON.parse(body);
        const text = parsed.content?.find(b => b.type === "text")?.text || "";
        if (!text) reject(new Error(`API réponse vide — body: ${body.slice(0,200)}`));
        else resolve(text);
      } catch (e) { reject(new Error(`Parse API : ${e.message} | body: ${body.slice(0,200)}`)); }
    });
  });
  req.setTimeout(180000, () => { req.destroy(); reject(new Error("Timeout 180s CONV-A")); });
  req.on("error", reject);
  req.write(payload);
  req.end();
});

// Génération du passeport après rédaction LLM
const MEPA_SCRIPTS = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";

let passeportData = null;
let passeportError = null;
let statut_global = "INCOMPLET";

try {
  const passeportPath = `/tmp/${wp_id}_passeport.json`;
  execSync(
    `/usr/bin/python3 ${MEPA_SCRIPTS}/mepa_passeport_schema.py ${data.result_path} SKIP SKIP ${passeportPath}`,
    { encoding: "utf8" }
  );
  const raw = execSync(`cat ${passeportPath}`, { encoding: "utf8" });
  passeportData = JSON.parse(raw.trim());
