} catch (e) {
  passeportError = e.message;
  passeportData = {
    "$schema":      "mepa-passeport-v2.0-fallback",
    "generated_at": new Date().toISOString(),
    "identite":     { wp_id, cluster: data.result_data?.meta?.cluster || "?" },
