    "statut_global":{ code: "INCOMPLET", label: "Passeport partiel (erreur script)" },
    "erreur_generation": passeportError
  };
}

return {
  json: {
    status:            "RAPPORT_RÉDIGÉ",
    wp_id,
    rapport_md,
    result_data:       data.result_data,
    audit_log:         data.audit_log,
    traj_diagn:        data.traj_diagn,
    concordance:       data.concordance,
    robustesse:        data.robustesse,
    rapport_n1:        rapport_n1,
