    cci_global:        data.cci_global ?? null,
    cci_result:        data.cci_result ?? null,
    verdict_cci:       data.verdict_cci ?? null,
    scores_resolus:    data.scores_resolus || {},
    statut_global,
    message: `Rapport rédigé (${rapport_md.length} chars)${passeportError ? " | [WARN] passeport partiel" : " | passeport généré"}`
  }
};

// NŒUD 7 — Export & Archivage (No-FS)
"use strict";
