  writeText(dst, JSON.stringify(data.passeport, null, 2));
  archived.passeport = dst;
}

if (data.rapport_md) {
  const dst = `${dirs.rapports}/${file_prefix_n7}_rapport.md`;
  writeText(dst, data.rapport_md);
  archived.rapport_md = dst;
}

const transit_conv_d = {
