    result_download: archived.result     || null,
    rapport_md_path: archived.rapport_md || null,
    passeport_path:  archived.passeport  || null,
    // Transmettre le contenu pour CONV-B audit (Nœud 6b) [CORRECTIF]
    rapport_md:      data.rapport_md     || "",
    result_data:     data.result_data    || {},
    audit_log:       data.audit_log      || {},
    traj_diagn:      data.traj_diagn,
    concordance:     data.concordance,
    robustesse:      data.robustesse,
    rapport_n1:      data.rapport_n1     || null,
