  ? (sim.stress_n2 || []).map(s => `  - ${s.label}: ${s.traj}`).join("\n")
  : "Non calculé";
const traj_attendue = result_data.meta?.trajectoire_attendue || "?";

const SYSTEM = `Tu es CONV-B, l'Auditeur Scientifique MEPA V6.2.
