VERDICT : CERTIFIE / REVISION_MINEURE / REVISION_MAJEURE / REJET
CERTIFIE = 5/5 ou anomalies mineures non bloquantes
REVISION_MINEURE = 1-2 anomalies C1/C2/C5 corrigeables sans re-simulation
REVISION_MAJEURE = anomalie C4 (narrative smoothing) OU anomalie C1 valeur cle
REJET = anomalie C1 trajectoire OU 3+ anomalies OU CCI<0.50

Reponds UNIQUEMENT en JSON pur sans markdown.`;

const USER = `WP: ${wp_id}
Trajectoire attendue : ${traj_attendue}
Trajectoire simulee : ${sim.traj || "?"}
FR_max : ${sim.FR_max || "?"} | t_bascule : ${sim.t_bascule ?? "null"}
dC_rel : ${sim.dC_rel ?? "null"} | dI_rel : ${sim.dI_rel ?? "null"}

