  "date_codage": "${new Date().toISOString().split("T")[0]}",
  "variables_codees": {
    "E_split": {"valeur": <float>, "justification": "<2-3 phrases avec γ si gamma, indicateurs chiffrés>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "gamma":   {"valeur": <float>, "justification": "<utilise γ dans le texte>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "A_d_eff": {"valeur": <float>, "justification": "<indicateurs chiffrés obligatoires>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "A_r_c":   {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "Cs":      {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "L_t":     {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}}
  },
  "commandes_mises_a_jour": {
    "E": <float E_split>, "gamma": <float gamma>,
    "R": <float normalisé A_d_eff>, "Mob": <float Cs>,
    "Rc": <float A_r_c>, "Rn": <float A_r_ne hardcodé>
  },
  "L0_mis_a_jour": <float L_t>,
  "resume_coherence": "<3-5 phrases — compatibilité scores avec trajectoire attendue et cluster>"
}`;

const payload = JSON.stringify({
  model: "claude-sonnet-4-20250514",
  max_tokens: 3000,
  system: SYSTEM,
  messages: [{ role: "user", content: USER }]
});

// ── Appel API Anthropic ──────────────────────────────────────────────────────
const conv_e_result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: "api.anthropic.com",
    path: "/v1/messages",
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": ANTHROPIC_API_KEY,
      "anthropic-version": "2023-06-01"
    }
  }, (res) => {
    let body = "";
    res.on("data", c => body += c);
    res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
        const raw = JSON.parse(body).content?.[0]?.text || "{}";
        const clean = raw.replace(/```json|```/g, "").trim();
        resolve(JSON.parse(clean));
      } catch(e) {
        reject(new Error(`Parse CONV-E: ${e.message} | raw: ${body.slice(0,200)}`));
      }
    });
  });
  req.setTimeout(120000, () => { req.destroy(); reject(new Error("Timeout 120s")); });
  req.on("error", reject);
  req.write(payload);
  req.end();
});

// ── Injecter les valeurs codées dans la fiche ────────────────────────────────
const vars_codees  = conv_e_result.variables_codees  || {};
const cmd_updates  = conv_e_result.commandes_mises_a_jour || {};
const l0_update    = conv_e_result.L0_mis_a_jour;

// Mettre à jour variables[k].valeur
const vars_updated = { ...vars_fiche };
for (const [k, v] of Object.entries(vars_codees)) {
  if (vars_updated[k]) {
    vars_updated[k] = {
      ...vars_updated[k],
      valeur:       v.valeur,
      justification: v.justification,
      sanity_check: { ...vars_updated[k].sanity_check, ...v.sanity_check },
      codeur:       "CONV-E",
      date_codage:  conv_e_result.date_codage
    };
  }
}

// Mettre à jour les commandes — mapping sélectif CONV-E
// RÈGLE V6.2 : E, gamma, Rc, Rn → mapping libre depuis variables codées
// R (A_d_eff) et Mob (Cs) → NE PAS écraser les valeurs normatives corpus
// T, Ref, Pop, EROI → structurels, jamais modifiés par CONV-E
const CMD_MAPPING_LIBRE = ["E", "gamma", "Rc", "Rn"];
const cmd_updated = { ...cmd_actuel };
for (const key of CMD_MAPPING_LIBRE) {
  if (cmd_updates[key] !== undefined && cmd_updates[key] !== null) {
    cmd_updated[key] = cmd_updates[key];
  }
}
// R et Mob : logguer la valeur CONV-E mais préserver la valeur normative
const r_conv_e   = cmd_updates["R"]   ?? null;
const mob_conv_e = cmd_updates["Mob"] ?? null;
if (r_conv_e !== null) {
  console.error("[CONV-E] cmd.R propose par CONV-E = " + r_conv_e + " -- valeur normative corpus preservee : " + cmd_actuel.R);
}
if (mob_conv_e !== null) {
  console.error("[CONV-E] cmd.Mob propose par CONV-E = " + mob_conv_e + " -- valeur normative corpus preservee : " + cmd_actuel.Mob);
}

// Mettre à jour L0 dans conditions_initiales
const ci_updated = { ...(data.conditions_initiales || {}) };
if (l0_update !== undefined && l0_update !== null) {
  ci_updated.L0 = l0_update;
}

// ── Retourner la fiche enrichie ──────────────────────────────────────────────
// Champs pipeline (non transmis dans la fiche racine — évite erreur C9)
const _conv_e_meta = {
  conv_e_raw:       conv_e_result,
  resume_coherence: conv_e_result.resume_coherence || "",
  nb_vars_codees:   Object.keys(vars_codees).length
};

return {
  json: {
    ...data,
    // Champs fiche — autorisés par RACINE_AUTORISEES
    variables:            vars_updated,
    commandes:            cmd_updated,
    conditions_initiales: ci_updated,
    statut:               "CODAGE CONV-E — EN ATTENTE AUDIT CONV-B",
    date_codage:          conv_e_result.date_codage || new Date().toISOString().split("T")[0],
    codeur:               "CONV-E",
    // Champs pipeline — préfixe _ exclu de la fiche mais lisibles par les nœuds suivants
    _conv_e_meta,
    _pipeline_message: `[CONV-E] ${wp_id} — ${Object.keys(vars_codees).length} variables codées`
  }
};

"use strict";
const { execSync } = require("child_process");
const data  = $input.item.json;
const wp_id = data.wp_id || "WP-INCONNU";
let cleaned = [];
let errors  = [];

// Patterns V1 — fichiers sans suffixe passe (rétrocompatibilité)
const patterns = [
  `_runner_config.json`, `_result.json`, `_n1_sensitivity.json`,
  `_fiche_conv_b.json`, `_fiche_conv_e_kappa.json`, `_cci_result.json`,
  `_passeport.json`, `_n2_optimiste.json`, `_n2_pessimiste.json`,
  `_n2_optimiste_result.json`, `_n2_pessimiste_result.json`, `_revision_counter.txt`
];
for (const suffix of patterns) {
  const path = `/tmp/${wp_id}${suffix}`;
  try { execSync(`rm -f ${path}`); cleaned.push(path); }
  catch(e) { errors.push(`${path}: ${e.message.slice(0,50)}`); }
}

// Suppression fichiers multi-passes V2 — WP-xxx_sim_N_* (tous suffixes)
// Couvre WP-xxx_sim_1_result.json, WP-xxx_sim_2_runner_config.json, etc.
try {
  execSync(`rm -f /tmp/${wp_id}_sim_*`);
  cleaned.push(`/tmp/${wp_id}_sim_* (multi-passes)`);
} catch(e) {
  errors.push(`sim_* cleanup: ${e.message.slice(0,50)}`);
}

return {
  json: {
    ...data,
    cleanup: { cleaned: cleaned.length, errors },
    message: `[CLEANUP] ${wp_id} — ${cleaned.length} fichiers /tmp/ supprimés`
  }
};

// ============================================================================
// NŒUD 16 — Consolidation Multi-passes [Post-Split out1]
// ============================================================================
// Position   : connecté sur out1 du Split in Batches (signal "done")
//              → s'exécute UNE SEULE FOIS après que toutes les passes ont
//              été archivées par N15.
//
// Entrée     : dernier item du Split (porte wp_id, zone, nb_passes_total)
//              + tous les fichiers archivés par N15 sur disque
//
// Sorties disque :
//   /data/mepa/outputs/cluster_XX/results/{wp_id}_consolidation.json
//   /data/mepa/outputs/cluster_XX/rapports/{wp_id}_consolidation.md
//
// En cas de passe manquante (runner échoué) :
//   → Consolide les passes disponibles + flag passes_manquantes[]
//
// Sources lues :
//   certification/{wp_id}_sim_N_passeport_compact.json  (trajectoires, CCI, robustesse)
//   cluster_XX/results/{wp_id}_sim_N_result.json         (F/R, stress N1/N2)
//   certification/{wp_id}_sim_N_cci.json                 (accord inter-codeurs par var)
//   sensitivity/{wp_id}_sim_N_n1.json                    (sensibilité paramétrique)
// ============================================================================

"use strict";
const fs = require("fs");
const { execSync } = require("child_process");

const data         = $input.item.json;
const wp_id        = data.wp_id        || "WP-INCONNU";
const zone         = data.zone_stratification || "LOI PHYSIQUE";
const nb_passes    = data.nb_passes_total ?? 3;
const BASE         = $env.MEPA_OUTPUT_DIR || "/data/mepa/outputs";
const cluster_raw  = data.llm_context?.cluster || data.cluster || "CX";
const cluster      = cluster_raw.replace(/[^A-Z0-9]/g, "");

// ── Répertoires ──────────────────────────────────────────────────────────────
const dirs = {
  results:      `${BASE}/cluster_${cluster}/results`,
  rapports:     `${BASE}/cluster_${cluster}/rapports`,
  passeports:   `${BASE}/passeports`,
  sensitivity:  `${BASE}/sensitivity`,
  certification:`${BASE}/certification`,
};
execSync(`mkdir -p ${Object.values(dirs).join(" ")}`);

// ── Helpers lecture sécurisée ─────────────────────────────────────────────────
function readJSON(path) {
  try { return JSON.parse(fs.readFileSync(path, "utf8")); }
  catch (_) { return null; }
}

// ── Lecture des N passes ──────────────────────────────────────────────────────
const passes_lues       = [];
const passes_manquantes = [];

for (let i = 1; i <= nb_passes; i++) {
  const sim = `sim_${i}`;
  const prefix_cert   = `${dirs.certification}/${wp_id}_${sim}`;
  const prefix_result = `${dirs.results}/${wp_id}_${sim}`;
  const prefix_sens   = `${dirs.sensitivity}/${wp_id}_${sim}`;

  const compact  = readJSON(`${prefix_cert}_passeport_compact.json`);
  const result   = readJSON(`${prefix_result}_result.json`);
  const cci      = readJSON(`${prefix_cert}_cci.json`);
  const n1       = readJSON(`${prefix_sens}_n1.json`);

  // Une passe est considérée manquante si le passeport compact est absent
  if (!compact) {
    passes_manquantes.push({ num: i, sim, raison: "passeport_compact introuvable" });
    continue;
  }

  // Extraire les métriques clés du result runner
  const sim_data  = result?.simulation || {};
  const vrd_data  = result?.verdict    || {};
  const meta_data = result?.meta       || {};
  const cmd_data  = result?.cmd_base   || {};

  // Résumé N1/N2 depuis le result runner (stress embarqué)
  const stress_n1 = result?.stress_n1 || {};
  const stress_n2 = result?.stress_n2 || [];
  const trajs_n2  = [...new Set(stress_n2.map(s => s.traj).filter(Boolean))];

  // Résumé CCI par variable
  const cci_details = cci?.details || [];
  const cci_par_var = Object.fromEntries(
    cci_details.map(d => [d.variable, {
      val_e:    d.val_a,
      val_b:    d.val_b,
      accord:   d.accord,
      action:   d.action,
    }])
  );

  // Résumé N1 sensitivity
  const n1_verdict       = n1?.verdict_n1 || null;
  const n1_vars_sensibles = n1?.variables_sensibles || [];
  const n1_params_sensibles = n1?.params_sensibles || [];

  passes_lues.push({
    num_passe:        i,
    sim_label:        sim,
    passe_label:      compact.passe_label    || null,
    zone:             compact.zone           || zone,
    // Trajectoire
    traj_attendue:    compact.traj_attendue,
    traj_diagn:       compact.traj_diagn,
    concordant:       compact.concordant,
    robustesse_n1:    compact.robustesse,
    statut_cert:      compact.statut_cert,
    // Métriques runner
    FR_max:           sim_data.FR_max        ?? null,
    FR_final:         sim_data.FR_final      ?? null,
    t_bascule:        sim_data.t_bascule     ?? null,
    dC_rel:           sim_data.dC_rel        ?? null,
    dI_rel:           sim_data.dI_rel        ?? null,
    I_final:          sim_data.I_final       ?? null,
    C_final:          sim_data.C_final       ?? null,
    // Stress N1 (depuis result runner)
    n1_opt_traj:      stress_n1.optimiste?.traj  || null,
    n1_pes_traj:      stress_n1.pessimiste?.traj || null,
    n1_pes_dI_rel:    stress_n1.pessimiste?.dI_rel ?? null,
    trajs_set_n1:     vrd_data.trajs_set_n1  || [],
    // Stress N2 (depuis result runner)
    trajs_n2_uniques: trajs_n2,
    bifurcations_n2:  trajs_n2.filter(t => t !== compact.traj_diagn),
    // CCI
    CCI_global:       compact.CCI            ?? null,
    CCI_par_variable: cci_par_var,
    // N1 sensitivity externe
    n1_verdict,
    n1_vars_sensibles,
    n1_params_sensibles,
    // Commandes appliquées dans cette passe
    cmd_effectifs: {
      E:     cmd_data.E     ?? null,
      gamma: cmd_data.gamma ?? null,
      Rc:    cmd_data.Rc    ?? null,
      T:     cmd_data.T     ?? null,
      R:     cmd_data.R     ?? null,
      EROI_start: cmd_data.EROI_start ?? null,
      EROI_end:   cmd_data.EROI_end   ?? null,
    },
    L0_effectif:      meta_data.y0_normalise?.[1] ?? null,
    // Popper
    RF1: compact.RF1 || null,
    RF2: compact.RF2 || null,
    p6_final: compact.p6_final ?? null,
  });
}

// ── Calculs de synthèse ───────────────────────────────────────────────────────
const nb_lus        = passes_lues.length;
const nb_manquantes = passes_manquantes.length;
const nb_concordants = passes_lues.filter(p => p.concordant).length;

// Toutes les trajectoires diagnostiquées
const toutes_trajs  = passes_lues.map(p => p.traj_diagn).filter(Boolean);
const trajs_uniques = [...new Set(toutes_trajs)];

// Robustesse globale inter-passes
const robustesse_globale =
  trajs_uniques.length === 0 ? "NON_CALCULE" :
  trajs_uniques.length === 1 ? "ROBUSTE"     :
  trajs_uniques.length === 2 ? "MÉTASTABLE"  : "FRAGILE";

// Trajectoire majoritaire
const traj_count = {};
toutes_trajs.forEach(t => traj_count[t] = (traj_count[t] || 0) + 1);
const traj_majoritaire = Object.entries(traj_count)
  .sort((a, b) => b[1] - a[1])[0]?.[0] || null;

// CCI agrégé (moyenne des CCI globaux disponibles)
const cci_vals = passes_lues.map(p => p.CCI_global).filter(v => v !== null);
const cci_moyen = cci_vals.length
  ? Math.round(cci_vals.reduce((a, b) => a + b, 0) / cci_vals.length * 10000) / 10000
  : null;
const cci_min = cci_vals.length ? Math.min(...cci_vals) : null;
const cci_max = cci_vals.length ? Math.max(...cci_vals) : null;

// Stabilité des CCI par variable (accord CONV-E/CONV-B cohérent entre passes ?)
const vars_suivies = ["E_split", "gamma", "A_d_eff", "A_r_c", "Cs", "L_t"];
const cci_par_var_consolide = {};
for (const v of vars_suivies) {
  const vals_e = passes_lues.map(p => p.CCI_par_variable?.[v]?.val_e).filter(x => x !== null && x !== undefined);
  const vals_b = passes_lues.map(p => p.CCI_par_variable?.[v]?.val_b).filter(x => x !== null && x !== undefined);
  const accords = passes_lues.map(p => p.CCI_par_variable?.[v]?.accord).filter(x => x !== null && x !== undefined);
  if (vals_e.length === 0) continue;
  const mean = arr => arr.length ? Math.round(arr.reduce((a,b)=>a+b,0)/arr.length * 100) / 100 : null;
  cci_par_var_consolide[v] = {
    val_e_moy:    mean(vals_e),
    val_b_moy:    mean(vals_b),
    taux_accord:  accords.length ? Math.round(accords.filter(Boolean).length / accords.length * 100) : null,
    nb_passes:    vals_e.length,
  };
}

// Bifurcations N2 inter-passes (quelles passes ont des bifurcations ?)
const passes_avec_bifurc = passes_lues
  .filter(p => p.bifurcations_n2.length > 0)
  .map(p => ({ sim: p.sim_label, bifurcations: p.bifurcations_n2 }));

// FR_max moyen et écart-type (sensibilité à la configuration)
const fr_vals = passes_lues.map(p => p.FR_max).filter(v => v !== null);
const fr_moy  = fr_vals.length ? Math.round(fr_vals.reduce((a,b)=>a+b,0)/fr_vals.length * 10000)/10000 : null;
const fr_std  = fr_vals.length > 1
  ? Math.round(Math.sqrt(fr_vals.map(v => (v-fr_moy)**2).reduce((a,b)=>a+b,0)/fr_vals.length) * 10000)/10000
  : null;

// ── Objet consolidation JSON ──────────────────────────────────────────────────
const consolidation = {
  // Identité
  wp_id,
  cluster,
  zone_stratification: zone,
  nb_passes_attendues: nb_passes,
  nb_passes_lues:      nb_lus,
  nb_passes_manquantes:nb_manquantes,
  passes_manquantes,
  generated_at:        new Date().toISOString(),

  // Verdict global
  verdict: {
    robustesse_globale,
    trajectoire_majoritaire:   traj_majoritaire,
    trajectoires_uniques:      trajs_uniques,
    concordance_taux:          `${nb_concordants}/${nb_lus}`,
    concordance_totale:        nb_concordants === nb_lus && nb_lus > 0,
    flag_passes_manquantes:    nb_manquantes > 0,
  },

  // CCI consolidé
  cci: {
    moyen:  cci_moyen,
    min:    cci_min,
    max:    cci_max,
    ecart:  cci_vals.length > 1 ? Math.round((cci_max - cci_min) * 10000)/10000 : null,
    seuil_certif: 0.75,
    toutes_certifiees: cci_vals.length > 0 && cci_min >= 0.75,
    par_variable: cci_par_var_consolide,
  },

  // Métriques runner consolidées
  runner: {
    FR_max_moyen:   fr_moy,
    FR_max_stddev:  fr_std,
    FR_max_min:     fr_vals.length ? Math.min(...fr_vals) : null,
    FR_max_max:     fr_vals.length ? Math.max(...fr_vals) : null,
    I_final_values: passes_lues.map(p => ({ sim: p.sim_label, I_final: p.I_final })),
  },

  // Robustesse N2
  n2: {
    passes_avec_bifurcations: passes_avec_bifurc,
    nb_passes_robustes_n2:    passes_lues.filter(p => p.bifurcations_n2.length === 0).length,
  },

  // Détail par passe (tableau compact)
  passes: passes_lues.map(p => ({
    sim:          p.sim_label,
    passe_label:  p.passe_label,
    traj_diagn:   p.traj_diagn,
    concordant:   p.concordant,
    robustesse:   p.robustesse_n1,
    FR_max:       p.FR_max,
    t_b:          p.t_bascule,
    CCI:          p.CCI_global,
    n1_pes_traj:  p.n1_pes_traj,
    bifurc_n2:    p.bifurcations_n2,
    cmd_E:        p.cmd_effectifs?.E,
    cmd_gamma:    p.cmd_effectifs?.gamma,
    cmd_Rc:       p.cmd_effectifs?.Rc,
    L0:           p.L0_effectif,
  })),
};

// ── Markdown de synthèse ──────────────────────────────────────────────────────
const taux_concordance = `${nb_concordants}/${nb_lus}`;
const cci_str = cci_moyen !== null ? `${cci_moyen} (min=${cci_min}, max=${cci_max})` : "N/C";
const manq_str = nb_manquantes > 0
  ? `\n> ⚠ **${nb_manquantes} passe(s) manquante(s)** : ${passes_manquantes.map(p => p.sim).join(", ")}\n`
  : "";

const lignes_passes = passes_lues.map(p => {
  const bifurc = p.bifurcations_n2.length > 0 ? `⚡ N2: ${p.bifurcations_n2.join(",")}` : "N2: stable";
  const n1pes  = p.n1_pes_traj && p.n1_pes_traj !== p.traj_diagn ? ` ⚡ N1pes→${p.n1_pes_traj}` : "";
  return `| ${p.sim_label} | ${p.passe_label || "-"} | ${p.traj_diagn} | ${p.concordant ? "✓" : "✗"} | ${p.robustesse_n1} | ${p.FR_max ?? "N/C"} | ${p.CCI_global ?? "N/C"} | ${bifurc}${n1pes} |`;
}).join("\n");

// CCI par variable
const lignes_cci = Object.entries(cci_par_var_consolide).map(([v, d]) =>
  `| ${v} | ${d.val_e_moy ?? "N/C"} | ${d.val_b_moy ?? "N/C"} | ${d.taux_accord !== null ? d.taux_accord + "%" : "N/C"} |`
).join("\n");

const rapport_md = `# Consolidation Multi-passes — ${wp_id}

**Zone :** ${zone} | **Passes :** ${nb_lus}/${nb_passes} lues | **Généré :** ${new Date().toISOString().split("T")[0]}
${manq_str}
---

## Verdict global

| Critère | Valeur |
|---|---|
| Robustesse inter-passes | **${robustesse_globale}** |
| Trajectoire majoritaire | \`${traj_majoritaire}\` |
| Trajectoires distinctes | ${trajs_uniques.join(" / ")} |
| Concordance | ${taux_concordance} passes concordantes |
| CCI moyen | ${cci_str} |
| Toutes passes CCI certifiées (≥0.75) | ${consolidation.cci.toutes_certifiees ? "✓ OUI" : "✗ NON"} |
| FR_max moyen | ${fr_moy ?? "N/C"} (σ=${fr_std ?? "N/C"}) |

---

## Détail par passe

| Passe | Label | Trajectoire | Concord. | Robustesse | FR_max | CCI | N2 / N1 pessimiste |
|---|---|---|---|---|---|---|---|
${lignes_passes}

---

## CCI par variable (accord CONV-E / CONV-B consolidé)

| Variable | Val. moy CONV-E | Val. moy CONV-B | Taux accord |
|---|---|---|---|
${lignes_cci || "| N/C | — | — | — |"}

---

## Robustesse N2 inter-passes

- Passes avec bifurcations N2 : ${passes_avec_bifurc.length > 0 ? passes_avec_bifurc.map(p => `${p.sim} (→${p.bifurcations.join(",")})`).join(", ") : "aucune"}
